async (params, browser) => {
  // Open Airtable table
  await browser.open(`${params.table_url}`)

  // Wait for grid to load
  await browser.waitForSelector('.dataRow, [data-rowindex], .headerRow', 15000)

  // Let grid fully render
  await browser.wait(2000)

  // Open search bar
  const open_search = await browser.evaluate(`const searchBtn = document.querySelector('[data-testid="search-input"], .searchInput, [aria-label="Find"], [aria-label="Search"], .toolbarButton[aria-label*="search" i], .toolbarButton[aria-label*="find" i]'); if (searchBtn) { searchBtn.click(); } else { document.dispatchEvent(new KeyboardEvent('keydown', { key: 'f', ctrlKey: true, bubbles: true })); } return { opened: true }`)

  // Wait for search bar to appear
  await browser.wait(1000)

  // Type query and scrape matching records
  const result = await browser.evaluate(`const query = params.query; const searchInput = document.querySelector('[data-testid="search-input"] input, .searchInput input, [placeholder*="Find" i], [placeholder*="Search" i], input[type="search"]'); if (!searchInput) throw new Error('Could not find search input field'); searchInput.focus(); const nativeSet = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeSet.call(searchInput, query); searchInput.dispatchEvent(new Event('input', { bubbles: true })); searchInput.dispatchEvent(new Event('change', { bubbles: true })); await new Promise(r => setTimeout(r, 2000)); const headers = []; document.querySelectorAll('.headerRow .header, .columnHeader, [data-columnid] .header, [role="columnheader"]').forEach(h => { headers.push(h.textContent?.trim() || ''); }); const matchingRows = []; const highlightedRows = document.querySelectorAll('.dataRow.searchHighlight, [data-rowindex].highlighted, .dataRow:has(.cellHighlight), .dataRow:has(mark), [role="row"]:has(.searchResult)'); const rowSource = highlightedRows.length > 0 ? highlightedRows : document.querySelectorAll('.dataRow, [data-rowindex], [role="row"]:not(.headerRow)'); for (let i = 0; i < Math.min(rowSource.length, 50); i++) { const row = rowSource[i]; const rowText = row.textContent || ''; if (highlightedRows.length === 0 && !rowText.toLowerCase().includes(query.toLowerCase())) continue; const cells = row.querySelectorAll('.cell, [data-columnid], [role="gridcell"]'); const rowData = {}; cells.forEach((cell, idx) => { const key = headers[idx] || 'col_' + idx; const text = cell.textContent?.trim()?.substring(0, 300) || ''; if (text) rowData[key] = text; }); if (Object.keys(rowData).length > 0) matchingRows.push(rowData); } return { query: query, headers: headers, result_count: matchingRows.length, rows: matchingRows }`)

  return result
}
